import android.app.Service
import android.content.Intent
import android.os.IBinder
import android.util.Log

class BackgroundTaskService : Service() {
    companion object {
        const val ACTION_SYNC_DATA = "com.yourapp.action.SYNC_DATA"
        const val ACTION_CLEANUP = "com.yourapp.action.CLEANUP"
        const val EXTRA_PARAM1 = "param1"
        const val EXTRA_PARAM2 = "param2"
        private const val TAG = "BackgroundTaskService"
    }

    override fun onBind(intent: Intent?): IBinder? = null

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        intent?.let { 
            when (it.action) {
                ACTION_SYNC_DATA -> handleDataSync(it)
                ACTION_CLEANUP -> handleCleanup(it)
                else -> Log.w(TAG, "Unknown action received")
            }
        }
        
        return START_NOT_STICKY
    }

    private fun handleDataSync(intent: Intent) {
        val param1 = intent.getStringExtra(EXTRA_PARAM1)
        val param2 = intent.getStringExtra(EXTRA_PARAM2)
        
        Thread {
            try {
                Log.d(TAG, "Starting data sync with params: $param1, $param2")
                // Simulate data synchronization
                Thread.sleep(2000)
                // Perform actual sync operations here
                Log.d(TAG, "Data sync completed")
            } catch (e: Exception) {
                Log.e(TAG, "Error during data sync", e)
            }
        }.start()
    }

    private fun handleCleanup(intent: Intent) {
        val param1 = intent.getStringExtra(EXTRA_PARAM1)
        
        Thread {
            try {
                Log.d(TAG, "Starting cleanup with param: $param1")
                // Simulate cleanup operations
                Thread.sleep(3000)
                // Perform actual cleanup operations here
                Log.d(TAG, "Cleanup completed")
            } catch (e: Exception) {
                Log.e(TAG, "Error during cleanup", e)
            }
        }.start()
    }
}